css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #070b18; color: white; }
.layout { display: flex; min-height: 100vh; }
.sidebar { width: 260px; background: #0d1117; border-right: 1px solid rgba(255,255,255,0.07); display: flex; flex-direction: column; padding: 24px 16px; flex-shrink: 0; }
.sidebar-brand { font-size: 22px; font-weight: 900; padding: 0 12px; margin-bottom: 32px; }
.sidebar-nav { flex: 1; display: flex; flex-direction: column; gap: 4px; }
.nav-item { display: flex; align-items: center; gap: 12px; padding: 12px 16px; border-radius: 12px; color: #6b7280; text-decoration: none; font-weight: 500; font-size: 14px; transition: all 0.2s; } .nav-item:hover { background: rgba(255,255,255,0.05); color: white; } .nav-item.active { background: rgba(99,102,241,0.15); color: #818cf8; font-weight: 600; }
.nav-icon { font-size: 16px; }
.sidebar-user { display: flex; align-items: center; gap: 12px; padding: 16px; background: rgba(255,255,255,0.04); border-radius: 12px; margin-top: 16px; }
.user-avatar { width: 36px; height: 36px; border-radius: 50%; background: linear-gradient(135deg, #6366f1, #8b5cf6); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 800; }
.user-name { font-size: 14px; font-weight: 600; } .user-role { font-size: 11px; color: #6b7280; }
.main { flex: 1; padding: 28px; overflow-y: auto; }
.topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 28px; }
.topbar h1 { font-size: 28px; font-weight: 800; } .topbar p { color: #6b7280; font-size: 14px; margin-top: 2px; }
.topbar-right { display: flex; align-items: center; gap: 16px; }
.search-box { display: flex; align-items: center; gap: 8px; padding: 10px 16px; border-radius: 12px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); } .search-box input { background: none; border: none; color: white; outline: none; font-size: 14px; width: 180px; }
.notif { position: relative; font-size: 20px; cursor: pointer; } .notif-dot { position: absolute; top: 0; right: 0; width: 8px; height: 8px; border-radius: 50%; background: #ef4444; }
.stats-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 24px; }
.stat-card { padding: 20px; border-radius: 16px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); display: flex; gap: 16px; align-items: center; }
.stat-icon { width: 48px; height: 48px; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 20px; flex-shrink: 0; } .purple { background: rgba(99,102,241,0.2); } .blue { background: rgba(59,130,246,0.2); } .green { background: rgba(34,197,94,0.2); } .orange { background: rgba(249,115,22,0.2); }
.stat-label { font-size: 12px; color: #6b7280; margin-bottom: 4px; } .stat-value { font-size: 22px; font-weight: 800; margin-bottom: 4px; } .stat-change { font-size: 12px; font-weight: 600; } .up { color: #22c55e; } .down { color: #ef4444; }
.content-grid { display: grid; grid-template-columns: 1.4fr 1fr; gap: 20px; }
.chart-card, .orders-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 24px; }
.card-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; } .card-header h3 { font-size: 16px; font-weight: 700; } .card-header select, .card-header a { background: rgba(255,255,255,0.07); border: none; color: #9ca3af; padding: 6px 12px; border-radius: 8px; font-size: 13px; cursor: pointer; text-decoration: none; }
.bar-chart { display: flex; align-items: flex-end; gap: 12px; height: 160px; }
.bar-wrap { flex: 1; display: flex; flex-direction: column; align-items: center; gap: 8px; height: 100%; } .bar-wrap span { font-size: 11px; color: #6b7280; }
.bar { width: 100%; border-radius: 6px; background: rgba(99,102,241,0.3); } .bar.accent { background: linear-gradient(180deg, #6366f1, #8b5cf6); }
.orders-list { display: flex; flex-direction: column; gap: 0; }
.order-item { display: flex; align-items: center; gap: 12px; padding: 14px 0; border-bottom: 1px solid rgba(255,255,255,0.05); font-size: 13px; }
.o-id { color: #6b7280; width: 50px; } .o-name { flex: 1; font-weight: 500; } .o-amount { font-weight: 700; width: 80px; text-align: right; }
.o-status { padding: 4px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; } .success { background: rgba(34,197,94,0.15); color: #22c55e; } .pending { background: rgba(234,179,8,0.15); color: #eab308; } .failed { background: rgba(239,68,68,0.15); color: #ef4444; }
